// Input validation helpers
function isValidSortColumn(col: string): col is keyof Product {
  const allowedColumns = ["name", "price", "rating", "created_at", "category", "brand"];
  return allowedColumns.includes(col);
}

function isValidSortOrder(order: string): order is "ASC" | "DESC" {
  return order === "ASC" || order === "DESC";
}

function sanitizePositiveNumber(value: unknown): number | null {
  if (value === undefined || value === null) return null;
  const num = Number(value);
  if (isNaN(num) || num < 0) return null;
  return num;
}

function sanitizeString(value: unknown): string | null {
  if (typeof value !== "string" || value.trim().length === 0) return null;
  // Limit length to prevent abuse
  return value.trim().substring(0, 200);
}

